 1	import * as React from 'react';
 2	import { PopoverPosition, Tooltip } from '@patternfly/react-core';
 3	import { HealthDetails } from './HealthDetails';
 4	import * as H from '../../types/Health';
 5	import { createIcon, createTooltipIcon } from '../../config/KialiIcon';
 6	import { healthIndicatorStyle } from '../../styles/HealthStyle';
 7	
 8	interface HealthIndicatorProps {
 9	  health?: H.Health;
10	  id: string;
11	  tooltipPlacement?: PopoverPosition;
12	}
13	
14	export const HealthIndicator: React.FC<HealthIndicatorProps> = (props: HealthIndicatorProps) => {
15	  const globalStatus = props.health ? props.health.getGlobalStatus() : H.NA;
16	
17	  if (props.health) {
18	    const icon = createIcon(globalStatus);
19	
20	    return (
21	      <Tooltip
22	        aria-label="Health indicator"
23	        content={
24	          <div>
25	            <strong>{globalStatus.name}</strong>
26	            <HealthDetails health={props.health} />
27	          </div>
28	        }
29	        position={PopoverPosition.auto}
30	        className={healthIndicatorStyle}
31	      >
32	        {createTooltipIcon(icon)}
33	      </Tooltip>
34	    );
35	  }
36	
37	  return <span />;
38	};

