  1	import * as React from 'react';
  2	import { mount, shallow } from 'enzyme';
  3	import { shallowToJson } from 'enzyme-to-json';
  4	
  5	import { HealthIndicator } from '../HealthIndicator';
  6	import { AppHealth, DEGRADED, FAILURE, HEALTHY, NOT_READY } from '../../../types/Health';
  7	import { setServerConfig } from '../../../config/ServerConfig';
  8	import { healthConfig } from '../../../types/__testData__/HealthConfig';
  9	import { createIcon } from 'config/KialiIcon';
 10	
 11	describe('HealthIndicator', () => {
 12	  beforeAll(() => {
 13	    setServerConfig(healthConfig);
 14	  });
 15	  it('renders when empty', () => {
 16	    // SMALL
 17	    let wrapper = shallow(<HealthIndicator id="svc" />);
 18	    expect(wrapper.html()).not.toContain('pficon');
 19	
 20	    // LARGE
 21	    wrapper = shallow(<HealthIndicator id="svc" />);
 22	    expect(wrapper.html()).not.toContain('pficon');
 23	  });
 24	
 25	  it('renders healthy', () => {
 26	    const health = new AppHealth(
 27	      'bookinfo',
 28	      'reviews',
 29	      [
 30	        { name: 'A', availableReplicas: 1, currentReplicas: 1, desiredReplicas: 1, syncedProxies: 1 },
 31	        { name: 'B', availableReplicas: 2, currentReplicas: 2, desiredReplicas: 2, syncedProxies: 2 }
 32	      ],
 33	      { inbound: {}, outbound: {}, healthAnnotations: {} },
 34	      { rateInterval: 600, hasSidecar: true, hasAmbient: false }
 35	    );
 36	
 37	    let wrapper = shallow(<HealthIndicator id="svc" health={health} />);
 38	    expect(shallowToJson(wrapper)).toMatchSnapshot();
 39	    let html = wrapper.html();
 40	    expect(html).toContain(shallow(createIcon(HEALTHY)).html());
 41	  });
 42	
 43	  it('renders workloads degraded', () => {
 44	    const health = new AppHealth(
 45	      'bookinfo',
 46	      'reviews',
 47	      [
 48	        { name: 'A', availableReplicas: 1, currentReplicas: 1, desiredReplicas: 10, syncedProxies: 1 },
 49	        { name: 'B', availableReplicas: 2, currentReplicas: 2, desiredReplicas: 2, syncedProxies: 2 }
 50	      ],
 51	      { inbound: {}, outbound: {}, healthAnnotations: {} },
 52	      { rateInterval: 600, hasSidecar: true, hasAmbient: false }
 53	    );
 54	
 55	    let wrapper = shallow(<HealthIndicator id="svc" health={health} />);
 56	    let html = wrapper.html();
 57	    expect(html).toContain(shallow(createIcon(DEGRADED)).html());
 58	  });
 59	
 60	  it('renders some scaled down workload', () => {
 61	    const health = new AppHealth(
 62	      'bookinfo',
 63	      'reviews',
 64	      [
 65	        { name: 'A', availableReplicas: 0, currentReplicas: 0, desiredReplicas: 0, syncedProxies: 0 },
 66	        { name: 'B', availableReplicas: 2, currentReplicas: 2, desiredReplicas: 2, syncedProxies: 2 }
 67	      ],
 68	      { inbound: {}, outbound: {}, healthAnnotations: {} },
 69	      { rateInterval: 600, hasSidecar: true, hasAmbient: false }
 70	    );
 71	
 72	    let wrapper = shallow(<HealthIndicator id="svc" health={health} />);
 73	    let html = wrapper.html();
 74	    expect(html).toContain(shallow(createIcon(NOT_READY)).html());
 75	  });
 76	
 77	  it('renders all workloads down', () => {
 78	    const health = new AppHealth(
 79	      'bookinfo',
 80	      'reviews',
 81	      [
 82	        { name: 'A', availableReplicas: 0, currentReplicas: 0, desiredReplicas: 0, syncedProxies: 0 },
 83	        { name: 'B', availableReplicas: 0, currentReplicas: 0, desiredReplicas: 0, syncedProxies: 0 }
 84	      ],
 85	      { inbound: {}, outbound: {}, healthAnnotations: {} },
 86	      { rateInterval: 600, hasSidecar: true, hasAmbient: false }
 87	    );
 88	
 89	    let wrapper = mount(<HealthIndicator id="svc" health={health} />);
 90	    let html = wrapper.html();
 91	    expect(html).toContain(mount(createIcon(NOT_READY)).html());
 92	  });
 93	
 94	  it('renders error rate failure', () => {
 95	    const health = new AppHealth(
 96	      'bookinfo',
 97	      'reviews',
 98	      [{ name: 'A', availableReplicas: 1, currentReplicas: 1, desiredReplicas: 1, syncedProxies: 1 }],
 99	      {
100	        inbound: { http: { '200': 0.5, '500': 0.5 } },
101	        outbound: { http: { '500': 0.4, '200': 2 } },
102	        healthAnnotations: {}
103	      },
104	      { rateInterval: 600, hasSidecar: true, hasAmbient: false }
105	    );
106	
107	    let wrapper = shallow(<HealthIndicator id="svc" health={health} />);
108	    let html = wrapper.html();
109	    expect(html).toContain(shallow(createIcon(FAILURE)).html());
110	  });
111	
112	  describe('proxy status section', () => {
113	    it('renders the degraded workloads', () => {
114	      const health = new AppHealth(
115	        'bookinfo',
116	        'reviews',
117	        [
118	          {
119	            name: 'A',
120	            availableReplicas: 2,
121	            currentReplicas: 2,
122	            desiredReplicas: 2,
123	            syncedProxies: 1
124	          }
125	        ],
